INSERT INTO `products` VALUES ('08493870-1db1-4e59-a42d-16c77f113aa3','软件激活','多邻国Super会员','多邻国DuoLingGo超级会员，官方正规渠道','本商品为 多邻国 Duolingo Super 会员，通过官方正规渠道开通。\n开通后可解锁多邻国完整高级功能，提升学习体验，适合长期语言学习用户。\n⭐ 无广告学习体验\n💗 无限爱心（错误不扣学习进度）\n📚 解锁高级课程与练习\n📊 学习进度与能力强化功能',30.00,NULL,197,876,'/uploads/products/1770298152855_048e87ff1e11988c.jpg','[\"/uploads/products/1770298152855_048e87ff1e11988c.jpg\"]','[\"热销\"]','ACTIVE',0,'2026-02-04 21:32:38.151','2026-03-01 20:43:44.531',0,3,32.29),('12059dcb-222a-4565-943c-3fe669edb6f6',NULL,'APPLE MUSIC 会员','Apple Music 苹果音乐家庭组拼车','高效便捷 实时发货\nApple Music：1亿首歌曲，全无广告干扰（美区一亿首歌曲，国区一千万首）\n\n根据地区选择对应规格\n\n1.苹果安卓均可加入\n2.要求没有加入别人的家庭组\n\n注意事项：美区需自备美区账号，且没加入其他家庭拼车',15.00,NULL,428,1823,'/uploads/products/1770297717276_47d64074a4feebc1.jpeg','[\"/uploads/products/1770297717276_47d64074a4feebc1.jpeg\"]','[\"热销\", \"拼车\"]','ACTIVE',0,'2026-02-04 21:06:01.687','2026-03-01 20:43:44.538',0,2,52.4),('1ba2caf3-1e77-4f41-be5b-b9a097ff9c78','音乐会员','Spotify Premium 会员','Spotify高级会员，无广告畅听，支持离线下载','【商品说明】\n本商品为 Spotify Premium 高级会员服务，开通后可畅享 Spotify 全部会员功能，适合日常听歌、通勤、学习、工作等场景使用。\n🎵 海量正版音乐资源\n🚫 无广告打扰\n📶 支持离线下载\n🔊 高音质播放体验\n【发货与使用方式】\n下单后根据页面提示获取会员使用方式\n使用指定 Spotify 账号登录或绑定\n登录成功后即可享受 Premium 会员权益\n本商品为虚拟服务，自动或人工发货',70.00,NULL,345,1282,'/uploads/products/1770298118340_0f1ffdbb3e1cf462.jpg','[\"/uploads/products/1770298118340_0f1ffdbb3e1cf462.jpg\"]','[\"热销\", \"音乐\"]','ACTIVE',0,'2026-02-04 21:42:02.447','2026-03-01 20:43:44.542',0,2,40.82),('25d505fb-8e11-40c7-bb2d-905c862899ec','软件激活','Notion Plus Edu教育版','EDU邮箱+教程升级','【拍下秒发】Notion 原账号升级 永久Edu plus 会员无需转移资料 定制 教育邮箱 Notion Edu Plus 无限存储\n\n直接给你edu邮箱，随机前缀。支持Notion原账号升级，同时支持新账号注册，带教程，新手无忧操作\n\n⬆️服务升级\n⭐️升级Notion教育版：\n原账号升级，无需转移资料，邮箱更换为教育邮箱。后续使用教育邮箱+密码或验证码登录\n。\nQ问：可以用多久？\nA答：邮箱域名有效期已续费10年（最长期限），而且还继续自动续费，Notion政策不变就一直可以用，无后顾之忧。\n\nNotion免费版和教育增强版的区别如下:\n• 上传文件无限制（免费版单文件限制为5mb）\n• 数据库自动化（免费版只有基础的按钮功能）\n• 解锁30天历史功能（免费版只有7天）\n• 访客数量100（免费版限制10个）\n• 拥有可自定义的公共主页 notion.site 域名（免费版无此功能）\n• 无限的同步数据库功能（免费版限制为1个）\n\n直接把你原来的Notion工作区升级为教育版，无需转移资料，无痛升级。\n\nNotion教育版是Notion官方给学生和教育工作者的优惠福利，属于官方合规渠道。',7.00,NULL,453,543,'/uploads/products/1770298096206_bc7abf77e09aecad.jpg','[\"/uploads/products/1770298096206_bc7abf77e09aecad.jpg\"]','[\"推荐\"]','ACTIVE',0,'2026-02-04 21:47:35.227','2026-03-01 20:43:44.548',0,0,24.68),('426ca931-18e6-4429-9204-98b39fcc36dc','视频会员','Netflix 高级会员','美区Netflix Premium会员｜4K超高清画质｜多设备','【商品说明】\n本商品为 美区 Netflix Premium 高级会员服务，支持 4K 超高清画质与多设备同时观看。\n内容资源丰富，适合追剧、电影、家庭娱乐等使用场景。\n🇺🇸 美区 Netflix 会员\n🎬 支持 4K Ultra HD 超高清\n📱 多设备同时观看\n🚫 无广告，纯净观影体验\n【发货与使用方式】\n下单后按页面提示获取账号信息 / 使用方式\n使用提供的账号登录 Netflix\n登录成功后即可观看 Premium 会员内容\n虚拟商品，系统自动或人工发货',15.50,NULL,230,1673,'/uploads/products/1770297755307_db7ebc220152b7fb.jpg','[\"/uploads/products/1770297755307_db7ebc220152b7fb.jpg\"]','[\"热销\", \"4K\"]','ACTIVE',0,'2026-02-04 21:45:11.222','2026-03-01 20:43:44.554',0,0,48.88),('4984fee1-b71b-4e84-bb29-e67738dbf9bc','社交账号','iPhone iCloud储存空间2T','iCloud扩容家庭共享拼车2T','苹果设备专属云端扩容服务，家庭组共享大容量存储，每人独立空间，照片/文件备份不卡顿，隐私数据互不可见。\n\n拍下后自动发操作指引，无需等待\n5分钟内就能加入，立刻使用，新手也能快速上手',15.00,NULL,715,1533,'/uploads/products/1770298248968_5147b761b1799622.jpg','[\"/uploads/products/1770298248968_5147b761b1799622.jpg\"]','[\"热销\", \"拼车\"]','ACTIVE',0,'2026-02-04 21:14:35.530','2026-03-01 20:43:44.558',0,2,46.19),('77e2095a-7a1f-4ef7-bb8a-dd982f55a2f6','视频会员','Disney+ Plus','Disney+ Plus，全区可用，不限内容','【会员权益】\nDisney+迪士尼+拼车车位，全区可用，不限内容，4K HDR，支持R18+ R21+，全设备都能用，独立车位，可设PIN码，中文字幕，漫威、星战、泰勒、国家地理等热门内容都能看。\n\n24小时自动发货，秒到账号，操作简单，省心省力。虚拟商品，一经发货不退不换，拍下即视为同意。',9.00,NULL,434,646,'/uploads/products/1770298134569_7b426f4b7c3def52.jpg','[\"/uploads/products/1770298134569_7b426f4b7c3def52.jpg\"]','[\"4K\", \"HDR\"]','ACTIVE',0,'2026-02-04 21:37:32.393','2026-03-01 20:43:44.570',0,0,26.89),('7cf0bd5e-9b12-45aa-b172-aceb4feb5eaa','683a940d-6bba-4eec-972d-3c32abaca526','Onepass CDK','CDK for Google One Student Verify','🔑 产品介绍\nVerifyKey CDK 是用于 VerifyKey 自动验证平台的激活码。购买后输入 CDK 即可获得对应次数的验证配额，系统将自动完成 SheerID 学生身份验证流程，帮助您快速通过各大平台的学生认证。\n✅ 支持平台\nGoogle Student（Google One AI Premium）\n📦 使用说明\n购买后获取 CDK 激活码（格式：VK-XXXX-XXXX-XXXX）\n在验证页面输入 CDK 激活\n粘贴验证链接，点击「开始验证」\n每次成功验证消耗 1 次配额（不成功会自动返还配额）\n⚠️ 注意事项\nCDK为虚拟商品，激活后不支持退款\n配额用完后需重新购买\n\n\n🔑 VerifyKey CDK Activation Code\nInstant Student Verification — Unlock Exclusive Education Discounts\n📌 Product Overview\nVerifyKey CDK is an activation code for the VerifyKey automated verification platform. Simply enter your CDK to receive verification credits. Our system automatically completes the SheerID student identity verification process, helping you pass student verification on major platforms quickly and effortlessly.\n✅ Supported Platforms\nGoogle Student (Google One AI Premium)\n✅ Key Features\nFully Automated: Paste your link, click submit — verification is handled automatically\nConcurrent Processing: Batch submit multiple verification requests simultaneously\nHigh Success Rate: Smart information matching to maximize approval probability\nReal-Time Updates: Live verification status with instant result feedback\nSecure & Reliable: Independent quota management — pay only for what you use\n📦 How to Use\nPurchase and receive your CDK code (format: VK-XXXX-XXXX-XXXX)\nEnter the CDK on the verification page to activate\nPaste your verification link(s) and click \"Start Verify\"\nEach successful verification consumes 1 credit',7.00,NULL,459,1437,'/uploads/products/1771486654954_de71bc8b504926c2.png','[\"/uploads/products/1771486654954_de71bc8b504926c2.png\"]','[\"AI\", \"CDK\"]','ACTIVE',0,'2026-02-19 08:21:26.835','2026-03-01 20:43:44.577',0,63,61.9),('80c57e7d-917e-4524-9db5-647d46e4b8a7','软件激活','Photoshop2026 AI填充','PS AI填充扩图正版 WIN|MAC 通用','【产品亮点】\n1. 官方正版授权 - 支持软件任意升级更新\n2. 双设备同时在线（Win/Mac/iOS全兼容）\n3. 免复杂激活 - 登录即用全套软件\n【服务承诺】\n下单马上 自动发货\n7x12小时在线技术指导\n注意：本产品为Adobe官方订阅账号，非破解版/共享账号\n【常见问题】\n问：能使用官方创建式AI？\n答：可以,百分百独享生成AI积分\n问：能更新软件吗？\n答：支持Creative Cloud所有版本更新\n问：支持多少设备登录？\n答：这是独享账号,你可以在2个不同设备使用\n问：保证使用天数？\n答：保证买多久质保多久',12.00,NULL,165,1625,'/uploads/products/1770298207998_b285fa3cbcefd3cb.jpeg','[\"/uploads/products/1770298207998_b285fa3cbcefd3cb.jpeg\"]','[\"AI\", \"正版\"]','ACTIVE',0,'2026-02-04 21:22:04.629','2026-03-01 20:43:44.583',0,2,48.16),('9d5acd01-5561-4619-8b09-fb54d5e997e7','683a940d-6bba-4eec-972d-3c32abaca526','Gemini Pro 成品号','Gemini3.0Pro 一年成品号现货秒发','Gemini3.0Pro 一年成品号现货秒发\n\n老号稳定性和持久性都是新号比不了的，新号用不了两个月就没了,质保一年！\n\n账号不回收，带一年geminipro会员，独享可改密可换绑。可用Nano banana,可用Veo3.1！3.0pro！\n\n质量保障在线秒发！稳定不跑路！\n\n也可升级自己号 不知道怎么升级自己号的可以问我\n\n✅ 官方渠道正品，享受 Gemini 3、nano banana pro 模型 有效期一年\n✅ 不占号，非共享，完全属于你\n✅ 售后支持，官方验证\n✅ 立即开通，方便快捷\n✅ 老号，稳定不封号（非常重要）\n\n独享账号可登入可改密 可添加二次验证\n手搓成品号+到手直接使用。质保一年，出问题直接换新',45.00,NULL,111,1824,'/uploads/products/1770643393487_a73ce9626cb77399.png','[\"/uploads/products/1770643393487_a73ce9626cb77399.png\"]','[\"AI，热销\"]','ACTIVE',0,'2026-01-31 17:52:13.101','2026-03-01 20:43:44.592',0,7,51.53),('c17745fe-6678-4aac-bff5-e4445f5f7af7','软件激活','Google Account 谷歌Gmail','谷歌Gmail邮箱账号｜可改密｜2FA','本商品为 Google Account 谷歌 Gmail 邮箱账号，可正常登录 Google 全套服务。\n账号状态正常，支持修改密码，并可自行绑定 2FA 两步验证，安全性高，适合长期使用。\n📧 Gmail 邮箱服务\n🔐 支持修改密码\n🔑 支持开启 / 绑定 2FA\n🌍 可用于 Google 相关产品与服务\n\n【使用方法】\n1、使用提供的账号信息登录 Gmail / Google\n2、登录成功后 第一时间修改密码\n3、按需绑定手机号或开启 2FA 两步验证\n4、正常使用邮箱及 Google 相关服务\n【使用须知】\n虚拟商品，一经发货 非质量问题不支持退款\n请勿用于任何违法、违规用途\n请及时登录并修改密码，避免长期不使用\n因用户自身操作、平台风控等原因导致的问题，卖家不承担责任\n【适用场景】\n海外平台账号注册\nGoogle 服务使用\n备用邮箱 / 工作邮箱\n隐私保护，避免使用主邮箱',7.30,NULL,98,647,'/uploads/products/1770298191150_fc31ec8cebaebd44.jpg','[\"/uploads/products/1770298191150_fc31ec8cebaebd44.jpg\"]','[\"推荐\"]','ACTIVE',0,'2026-02-04 21:27:07.284','2026-03-01 20:43:44.598',0,6,27.86),('caec3922-010e-4810-8fd7-cf5fce5b1256','683a940d-6bba-4eec-972d-3c32abaca526','Cursor Pro 一年','一年cursor Pro 现价低到骨折｜独享EDU可改密','可改密！质保6个月！cursor直登！！！\n不需要任何东西，直接登录可以使用\n一年cursor Pro=官方240美金，现价低到骨折｜独享EDU可改密｜无限Auto\n\n官方价值约240美元/年，这里一口价搞定一年权益\n真实EDU认证，账号独享可改密，安全性>共号/拼车\n无限Tab补全、Auto/Agents全开，研发/写作/脚本效率倍增\n赠EDU邮箱：学生折扣平台通用，1个月即可回本\n质保 6 个月\n\n质保要求：质保6月，不能使用再补一个。只要是正常使用被封禁的情况下才给补，如以使用超额量扣费不成而不能使用的账号情况下，不补',300.00,1600.00,28,562,'/uploads/products/1770643428545_37496cf88d02c470.png','[\"/uploads/products/1770643428545_37496cf88d02c470.png\"]','[\"AI\"]','ACTIVE',0,'2026-02-03 18:25:09.563','2026-03-01 20:43:44.603',0,4,25.24),('f3d04c8b-c851-4f5e-bd90-f7bbefe638a5','视频会员','Emby影视库 ','直连｜4K｜HDR｜Emby影视库','EMBY影视库超值！稳定运行数年，有稳定活跃会员群！适合tv+、安卓TV及Mac、PC、iPhone、安卓手机平板等设备！\n【本影视库优势】：\n1.更新快又多，平均每天更新上百集、部剧集和电影；\n2.支持直连，无需各类科学工具；\n3.价格亲民，性价比高，充值年度会员更超值；\n\n汇集全球各地影视综艺纪录片，天天看不重样！',15.90,NULL,249,470,'/uploads/products/1770298229216_7253f4fa38eb1fba.jpg','[\"/uploads/products/1770298229216_7253f4fa38eb1fba.jpg\"]','[\"4K\", \"HDR\"]','ACTIVE',0,'2026-02-04 21:18:58.831','2026-03-01 20:43:44.607',0,3,23.59),('f67a7ec4-e65a-4cbe-b757-b8d83656eaa6','社交账号','Google Voice 虚拟手机号','Google提供的美国虚拟号，支持接收短信和通话，购买后即可使用','【商品特点】\n🇺🇸 美国虚拟号码\n📩 支持短信验证码\n📞 支持拨打 / 接听电话\n📦 自动发货，到账即用\n【使用说明】\n请勿用于违法或违规用途\n避免长期不登录或异常操作\n【适用场景】\n账号注册 / 验证码接收 / 海外平台使用\n【特殊说明】\n老号GV更容易转移到自己的Google账号',30.00,NULL,81,1868,'/uploads/products/1770298270885_ad939ad7658a5c22.jpg','[\"/uploads/products/1770298270885_ad939ad7658a5c22.jpg\"]','[]','ACTIVE',0,'2026-02-04 20:57:54.529','2026-03-01 20:43:44.611',0,4,53.68);
